#include <bits/stdc++.h>
using namespace std;int n,m,a,b,d[10001],c[10001];vector<int>v[10001];int D(int x){if(c[x])return 0;c[x]=1;int t=v[x].size();int s=1;for(int i=0;i<t;i++)s+=D(v[x][i]);return s;}main(int i){scanf("%d%d",&n,&m);for(i=0;i<m;i++,v[b].push_back(a))scanf("%d%d",&a,&b);int C=0;for(i=1;i<=n;i++){for(int j=1;j<=n;j++)c[j]=0;d[i]=D(i);C=max(C,d[i]);}for(i=1;i<=n;i++)if(C==d[i])printf("%d ",i);}